package connectors.documentum.connector.org.apache.manifoldcf.crawler.connectors.dctm;

protected class SystemMetadataDescription { protected String pathAttributeName ; protected Map pathMap = new HashMap ( ) ; protected MatchMap matchMap = new MatchMap ( ) ; public SystemMetadataDescription ( DocumentSpecification spec ) throws ManifoldCFException { pathAttributeName = null ; int i = 0 ; while ( i < spec . getChildCount ( ) ) { SpecificationNode n = spec . getChild ( i ++ ) ; if ( n . getType ( ) . equals ( CONFIG_PARAM_PATHNAMEATTRIBUTE ) ) pathAttributeName = n . getAttributeValue ( "value" ) ; else if ( n . getType ( ) . equals ( CONFIG_PARAM_PATHMAP ) ) { String pathMatch = n . getAttributeValue ( "match" ) ; String pathReplace = n . getAttributeValue ( "replace" ) ; matchMap . appendMatchPair ( pathMatch , pathReplace ) ; } } } public String getPathAttributeName ( ) { return pathAttributeName ; } public String [ ] getPathAttributeValue ( IDocumentumObject object ) throws DocumentumException , RemoteException , ManifoldCFException { String [ ] paths = object . getFolderPaths ( pathMap ) ; String [ ] rval = new String [ paths . length ] ; int i = 0 ; while ( i < paths . length ) { rval [ i ] = matchMap . translate ( paths [ i ] ) ; i ++ ; } return rval ; } }